onClick:
{{
  (() => {
    const motivo = String(inpDirUpdateMotivo.text || "").trim();
    const password = String(inpDirUpdatePassword.text || "").trim();
    const entity = appsmith.store.cp_update_context?.entity;
    const mode = appsmith.store.cp_update_context?.mode || "UPDATE";

    if (!motivo) {
      showAlert("DEBE INGRESAR EL MOTIVO DE ACTUALIZACIÓN.", "warning");
      return;
    }

    if (!password) {
      showAlert("DEBE INGRESAR LA CONTRASEÑA.", "warning");
      return;
    }

    if (!entity) {
      showAlert("NO HAY CONTEXTO DE ACTUALIZACIÓN.", "error");
      return;
    }

    if (entity === "CONDUCTOR") {
      if (!slDirCondTipoDocumento.selectedOptionValue) {
        showAlert("EL TIPO DE DOCUMENTO ES OBLIGATORIO.", "warning");
        return;
      }

      if (!inpDirCondNombre.text?.trim()) {
        showAlert("EL NOMBRE DEL CONDUCTOR ES OBLIGATORIO.", "warning");
        return;
      }

      if (!inpDirCondDocumento.text?.trim()) {
        showAlert("EL DOCUMENTO DEL CONDUCTOR ES OBLIGATORIO.", "warning");
        return;
      }

      if (!inpDirCondLicencia.text?.trim()) {
        showAlert("LA LICENCIA DEL CONDUCTOR ES OBLIGATORIA.", "warning");
        return;
      }

      if (!msDirCondCategoriaLicencia.selectedOptionValues?.length) {
        showAlert("LA CATEGORÍA DE LICENCIA ES OBLIGATORIA.", "warning");
        return;
      }

      if (!dpDirCondVencimientoLicencia.selectedDate) {
        showAlert("LA FECHA DE VENCIMIENTO DE LICENCIA ES OBLIGATORIA.", "warning");
        return;
      }

      if (!inpDirCondTelefono.text?.trim()) {
        showAlert("EL TELÉFONO DEL CONDUCTOR ES OBLIGATORIO.", "warning");
        return;
      }

      if (!inpDirCondEmail.text?.trim()) {
        showAlert("EL EMAIL DEL CONDUCTOR ES OBLIGATORIO.", "warning");
        return;
      }
    }

    if (entity === "VEHICULO") {
      if (!inpDirVehPlaca.text?.trim()) {
        showAlert("LA PLACA DEL VEHÍCULO ES OBLIGATORIA.", "warning");
        return;
      }

      if (!slDirVehTipoVehiculo.selectedOptionValue) {
        showAlert("EL TIPO DE VEHÍCULO ES OBLIGATORIO.", "warning");
        return;
      }

      if (!slDirVehMarca.selectedOptionValue) {
        showAlert("LA MARCA DEL VEHÍCULO ES OBLIGATORIA.", "warning");
        return;
      }

      if (!inpDirVehModelo.text?.trim()) {
        showAlert("EL MODELO DEL VEHÍCULO ES OBLIGATORIO.", "warning");
        return;
      }

      if (!slDirVehColor.selectedOptionValue) {
        showAlert("EL COLOR DEL VEHÍCULO ES OBLIGATORIO.", "warning");
        return;
      }

      if (!inpDirVehCapacidadKg.text?.trim()) {
        showAlert("LA CAPACIDAD DEL VEHÍCULO ES OBLIGATORIA.", "warning");
        return;
      }

      if (!inpDirVehSoatNo.text?.trim()) {
        showAlert("EL SOAT DEL VEHÍCULO ES OBLIGATORIO.", "warning");
        return;
      }

      if (!dpDirVehSoatVencimiento.selectedDate) {
        showAlert("LA FECHA DE VENCIMIENTO DEL SOAT ES OBLIGATORIA.", "warning");
        return;
      }
    }

    qDirAuthUsuario.run(
      () => {
        if ((qDirAuthUsuario.data || []).length === 0) {
          showAlert("CONTRASEÑA INCORRECTA O USUARIO SIN PERMISO.", "error");
          return;
        }

        if (entity === "CONDUCTOR") {
          const queryConductor =
            mode === "CREATE"
              ? bkDirCrearConductor
              : bkDirActualizarConductor;

          queryConductor.run(
            () => {
              qCpBuscarConductorPorDocumento.run();

              closeModal("mdlDirectorioUpdate");
              JS_CarguePlanta.clearDirectorioUpdateModal();

              showAlert(
                mode === "CREATE"
                  ? "CONDUCTOR CREADO CORRECTAMENTE."
                  : "CONDUCTOR ACTUALIZADO CORRECTAMENTE.",
                "success"
              );
            },
            () => {
              showAlert(
                mode === "CREATE"
                  ? "NO SE PUDO CREAR EL CONDUCTOR."
                  : "NO SE PUDO ACTUALIZAR EL CONDUCTOR.",
                "error"
              );
            }
          );
          return;
        }

        if (entity === "VEHICULO") {
          const queryVehiculo =
            mode === "CREATE"
              ? bkDirCrearVehiculo
              : bkDirActualizarVehiculo;

          queryVehiculo.run(
            () => {
              qCpBuscarVehiculoPorPlaca.run();
              qCpVehiculosResumen.run();

              closeModal("mdlDirectorioUpdate");
              JS_CarguePlanta.clearDirectorioUpdateModal();

              showAlert(
                mode === "CREATE"
                  ? "VEHÍCULO CREADO CORRECTAMENTE."
                  : "VEHÍCULO ACTUALIZADO CORRECTAMENTE.",
                "success"
              );
            },
            () => {
              showAlert(
                mode === "CREATE"
                  ? "NO SE PUDO CREAR EL VEHÍCULO."
                  : "NO SE PUDO ACTUALIZAR EL VEHÍCULO.",
                "error"
              );
            }
          );
          return;
        }

        showAlert("NO HAY CONTEXTO DE ACTUALIZACIÓN.", "error");
      },
      () => {
        showAlert("NO SE PUDO VALIDAR LA CONTRASEÑA.", "error");
      }
    );
  })()
}}
